// RAII wrapper for connection handles
class ScopedConnection {
public:
    ScopedConnection(ConnectionPool& pool, int timeout_ms = 5000)
        : pool_(pool), handle_(pool.acquire(timeout_ms)) {}
    
    ~ScopedConnection() {
        if (handle_.is_valid()) {
            pool_.release(handle_);
        }
    }
    
    // No copy
    ScopedConnection(const ScopedConnection&) = delete;
    ScopedConnection& operator=(const ScopedConnection&) = delete;
    
    // Move
    ScopedConnection(ScopedConnection&& other) noexcept
        : pool_(other.pool_), handle_(other.handle_) {
        other.handle_ = ConnectionHandle::invalid();
    }
    
    ConnectionHandle handle() const { return handle_; }
    bool is_valid() const { return handle_.is_valid(); }
    
    int send(const char* data, size_t len) {
        return pool_.send(handle_, data, len);
    }
    
    int recv(char* buf, size_t len) {
        return pool_.recv(handle_, buf, len);
    }
    
    // Manual retry after error
    bool retry() {
        return pool_.retry(handle_);
    }

private:
    ConnectionPool& pool_;
    ConnectionHandle handle_;
};

// Network client that uses the connection pool
class NetworkClient {
public:
    NetworkClient(const std::string& host, int port,
                  size_t min_pool_size = 2, size_t max_pool_size = 10,
                  int max_retries = 3)
    {
        ConnectionConfig config;
        config.host = host;
        config.port = port;
        config.max_retries = max_retries;
        config.retry_delay_ms = 50;
        config.connect_timeout_ms = 5000;
        config.idle_timeout_ms = 30000;
        
        pool_ = std::make_unique<ConnectionPool>(config, min_pool_size, max_pool_size);
    }
    
    ~NetworkClient() {
        if (pool_) {
            pool_->shutdown();
        }
    }
    
    // Send a request and receive a response
    // Returns response string, empty on failure
    std::string request(const std::string& data, int max_retries = 3) {
        ScopedConnection conn(*pool_);
        
        if (!conn.is_valid()) {
            std::cerr << "[NetworkClient] Failed to acquire connection from pool" << std::endl;
            return "";
        }
        
        for (int attempt = 0; attempt <= max_retries; ++attempt) {
            int sent = conn.send(data.c_str(), data.size());
            if (sent < 0) {
                std::cerr << "[NetworkClient] Send failed, attempt " << attempt + 1 << std::endl;
                if (attempt < max_retries) {
                    if (!conn.retry()) {
                        std::cerr << "[NetworkClient] Retry reconnection failed" << std::endl;
                        continue;
                    }
                }
                continue;
            }
            
            char buf[4096];
            int received = conn.recv(buf, sizeof(buf) - 1);
            if (received < 0) {
                std::cerr << "[NetworkClient] Recv failed, attempt " << attempt + 1 << std::endl;
                if (attempt < max_retries) {
                    if (!conn.retry()) {
                        std::cerr << "[NetworkClient] Retry reconnection failed" << std::endl;
                        continue;
                    }
                }
                continue;
            }
            
            buf[received] = '\0';
            return std::string(buf, received);
        }
        
        return "";
    }
    
    // Fire and forget send
    bool send(const std::string& data) {
        ScopedConnection conn(*pool_);
        if (!conn.is_valid()) return false;
        
        int result = conn.send(data.c_str(), data.size());
        return result >= 0;
    }
    
    // Get pool statistics
    ConnectionPool::Stats stats() const {
        return pool_->get_stats();
    }
    
    // Manual access to pool for advanced use
    ConnectionPool& pool() { return *pool_; }

private:
    std::unique_ptr<ConnectionPool> pool_;
};

